104→    @Override
105→    public String createMigrationTask(List<Long> spaceNodeIds, String targetSpaceId, String sourceSpaceId, Long userId, Boolean isRemained, Long targetParentNodeId) {
106→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
107→        String email = user.getEmail();
108→        Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
109→        // 为了尽量保持原 spaceNodeTree 的相对顺序, 直接拉整个树再筛选
110→        List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
111→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
112→        List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream().map(SpaceAppRelVo::new).toList();
113→
114→        // 目前每个服务都只会执行一种迁移逻辑, MigrationTypeEnum直接由服务环境判断, mirror服务只执行跨服务器迁移, 其它的都是服务器内迁移
115→        String taskId;
116→        if (constProperties.isMirror()) {
117→            taskId = collabspaceGrpcClientService.createSpaceNodeMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps, targetParentNodeId);
118→        } else {
119→            taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
120→                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained, targetParentNodeId);
121→        }
122→
123→        log.info("createMigrationTask: taskId={}, sourceNodeIds={}, targetSpaceId={}, sourceSpaceId={}, userId={}, targetParentNodeId={}, filteredTreeSize={}",
124→                taskId, spaceNodeIds, targetSpaceId, sourceSpaceId, userId, targetParentNodeId, spaceNodeTree.size());
125→
126→        return taskId;
127→    }
