129→    @Override
130→    public String createBatchMigrationTask(List<BatchMigrationItem> items,
131→                                           String targetSpaceId, Long userId, Boolean isRemained) {
132→        String batchId = "batch-" + System.currentTimeMillis() + "-" + UUID.randomUUID().toString().substring(0, 6);
133→        log.info("[lbl][2122-文件迁移][Migration][CREATE] 开始创建批量迁移, batchId={}, targetSpaceId={}, sourceCount={}, isRemained={}",
134→                batchId, targetSpaceId, items.size(), isRemained);
135→
136→        // 提前查询用户信息，避免循环内重复 gRPC 调用
137→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
138→        String email = user.getEmail();
139→
140→        for (BatchMigrationItem item : items) {
141→            String sourceSpaceId = item.getSourceSpaceId();
142→            List<Long> spaceNodeIds = item.getSpaceNodeIds();
143→
144→            Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
145→
146→            List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
147→            List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
148→            List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream()
149→                    .map(SpaceAppRelVo::new).toList();
150→
151→            String taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
152→                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained, null);
153→
154→            // 更新子任务的 batchId
155→            SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
156→            task.setBatchId(batchId);
157→            spaceNodeMigrationTaskService.updateById(task);
158→
159→            log.info("[lbl][2122-文件迁移][Migration][CREATE] 批量迁移子任务已创建, batchId={}, taskId={}, sourceSpaceId={}, nodeCount={}",
160→                    batchId, taskId, sourceSpaceId, spaceNodeIds.size());
161→        }
162→
163→        log.info("[lbl][2122-文件迁移][Migration][CREATE] 批量迁移任务创建完成, batchId={}, totalSubTasks={}", batchId, items.size());
164→        return batchId;
165→    }
