167→    @Override
168→    public String acceptMigrationTask(List<TreeNode<SpaceNodeVo>> spaceNodeTree, String email, String targetSpaceId,
169→                                      String sourceSpaceId, List<SpaceAppRelVo> appRels, Integer migrationType, Boolean isRemained, Long targetParentNodeId) {
170→        if (CollectionUtils.isEmpty(spaceNodeTree) || StringUtils.isBlank(targetSpaceId) || StringUtils.isBlank(email) || StringUtils.isBlank(sourceSpaceId)) {
171→            log.error("email={}, targetSpaceId={}, sourceSpaceId={}", email, targetSpaceId, sourceSpaceId);
172→            throw new BusinessException("acceptMigrationTask: empty or invalid arguments");
173→        }
174→
175→        String taskId = sourceSpaceId + "-" + targetSpaceId + "-" + System.currentTimeMillis();
176→
177→        SpaceNodeMigrationTaskEntity spaceNodeMigrationTaskEntity = SpaceNodeMigrationTaskEntity.builder()
178→                .taskId(taskId)
179→                .sourceSpaceId(sourceSpaceId)
180→                .targetSpaceId(targetSpaceId)
181→                .email(email)
182→                .originTree(JSONUtil.toJsonStr(spaceNodeTree))
183→                .sourceSpaceAppRels(JSONUtil.toJsonStr(appRels))
184→                .status(SpaceNodeMigrationTaskStatusEnum.PENDING.getValue())
185→                .type(migrationType)
186→                .isRemained(isRemained)
187→                .targetParentNodeId(targetParentNodeId)
188→                .build();
189→        spaceNodeMigrationTaskService.save(spaceNodeMigrationTaskEntity);
190→
191→        SpaceNodeMigrationMessage message = SpaceNodeMigrationMessage.builder()
192→                .taskId(taskId)
193→                .build();
194→        rabbitMqSender.directSend(SPACE_NODE_MIGRATION_EXCHANGE, SPACE_NODE_MIGRATION_KEY, JSONUtil.toJsonStr(message));
195→
196→        log.info("acceptMigrationTask: taskId={}, email={}, targetSpaceId={}, sourceSpaceId={}, targetParentNodeId={}, treeSize={}",
197→                taskId, email, targetSpaceId, sourceSpaceId, targetParentNodeId, spaceNodeTree.size());
198→
199→        return taskId;
200→    }
