208→        List<TreeNode<SpaceNodeVo>> spaceNodeTree = TreeUtil.filterByRelIds(spaceNodeTreeOrigin, targetNodeIds);
209→
210→        checkCopy(spaceNodeTree, targetSpaceId);
211→
212→        MigrationTypeEnum migrationType = MigrationTypeEnum.fromValue(MigrationTypeEnum.INTRA_SERVER.getValue());
213→
214→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
215→        String email = user.getEmail();
216→
217→        MigrationConfig migrationConfig = MigrationConfig.builder()
