221→        SpaceNodeMigrationResult overallResult = appMigrationChain.executeMigration(
222→                spaceNodeTree,
223→                targetSpaceId,
224→                sourceSpaceId,
225→                migrationType,
226→                migrationConfig
227→        );
228→
229→        // 迁移中遇到错误抛异常并终止迁移
