244→            spaceNodeEntityList.stream().filter(o -> o.getAppSpaceNodeId().equals(v)).
245→                    findFirst().ifPresent(spaceNodeEntity -> vo.setAioSpaceNodeId(spaceNodeEntity.getId().toString()));
246→            copyFileVoList.add(vo);
247→
248→        });
249→        return copyFileVoList;
