305→            log.warn("Migration had errors: {}", overallResult.getErrorMessage());
306→            throw new BusinessException(overallResult.getErrorMessage());
307→        }
308→
309→        TreeNode<SpaceNodeVo> node = spaceNodeTree.stream().filter(o -> o.getData().getId().equals(spaceNodeId)).findFirst().orElse(null);
310→        String snapShotId = null;
311→        if (node != null) {
312→            snapShotId = overallResult.getNodeIdMapping().get(String.valueOf(node.getData().getAppSpaceNodeId()));
313→        }
314→        if (snapShotId == null){
315→            throw new BusinessException("copy file error");
316→        }
317→        entity = CollabspaceVersionSnapshotEntity.builder().snapshotName(snapshotName).snapshotId(snapShotId).nodeId(spaceNodeId)
318→                .operatorId(0L).snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue()).build();
