323→                .name(snapshotName)
324→                .type(type)
325→                .description("")
326→                .spaceId(sourceSpaceId)
327→                .createdBy(userId)
328→                .updatedBy(userId)
329→                .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
330→                .build();
331→
332→        spaceNodeService.save(spaceNodeEntity);
